defmodule SecondLargest do
  @doc """
  Finds the second largest number in a list of integers.
  Assumes the list contains at least two distinct numbers.
  """
  @spec find_second_largest([integer()]) :: integer()
  def find_second_largest([first | rest]) do
    Enum.reduce(rest, {first, nil}, fn num, {max, second} ->
      cond do
        num > max -> {num, max}
        num < max and (second == nil or num > second) -> {max, num}
        true -> {max, second}
      end
    end)
    |> elem(1)
  end
end

