def anagrams(strs):
    anag = {}
    result = []
    for str in strs:
        s = ''.join(sorted(str))
        if (s in anag):
            anag[s].append(str)
        else:
            anag[s] = [str]
    for str in anag:
        if(len(anag[str])>1):
            result.extend(anag[str])
    return result

def max_ones(arr, k):
    left = 0
    max_len = 0
    zero_count = 0

    for right in range(len(arr)):
        if arr[right] == 0:
            zero_count += 1

        while zero_count > k:
            if arr[left] == 0:
                zero_count -= 1
            left += 1

        max_len = max(max_len, right - left + 1)

    return max_len

