defmodule StringFrequency do
  @doc """
  Finds the most frequent character in a string and returns its count.
  """
  @spec frequent_char(String.t()) :: non_neg_integer()
  def frequent_char(s) when is_binary(s) do
    String.graphemes(s)
    |> Enum.reduce({%{}, 0}, fn char, {counts, max_count} ->
      new_count = Map.get(counts, char, 0) + 1
      {Map.put(counts, char, new_count), max(new_count, max_count)}
    end)
    |> elem(1)
  end

  def frequent_char(_), do: raise(ArgumentError, "expected a string")
end

